# ---------------------------------------------------------------------------
# Fallback scorer: uses profile data + lemma knowledge when pair not in table
# ---------------------------------------------------------------------------
def fallback_score(src_lemma, tgt_lemma, src_gloss, tgt_gloss, profile):
    """
    Systematic fallback for pairs not in the hand-scored table.
    Uses masadiq definition text keyword matching.
    """
    tgt_lower = tgt_lemma.lower().strip()
    src_gl = (src_gloss or "").lower()
    tgt_gl = (tgt_gloss or "").lower()

    # Build a combined text from the Arabic profile
    masadiq = profile.get("masadiq", {}) or {}
    mafahim = profile.get("mafahim", {}) or {}
    status = profile.get("lookup_status", "")

    short_gloss = (masadiq.get("short_gloss") or "").lower()
    definition = (masadiq.get("definition") or "").lower()
    meaning_text = (masadiq.get("meaning_text") or "").lower()
    axial = (mafahim.get("axial_meaning") or "").lower()
    ara_text = short_gloss + " " + definition[:200] + " " + meaning_text[:200] + " " + axial

    # If target lemma or gloss appears in Arabic text → high score
    if tgt_lower in ara_text or (tgt_gl and tgt_gl in ara_text):
        return (0.82, f"target '{tgt_lemma}' found in Arabic masadiq/definition text.",
                f"{src_lemma} → {tgt_lemma}", "masadiq_direct")

    # If source gloss directly matches target
    if src_gl and tgt_lower in src_gl:
        return (0.88, f"source gloss '{src_gl}' directly names target '{tgt_lemma}'.",
                f"{src_lemma} ({src_gl}) → {tgt_lemma}", "masadiq_direct")

    if tgt_gl and src_gl and tgt_gl in src_gl:
        return (0.85, f"target gloss '{tgt_gl}' found in source gloss '{src_gl}'.",
                f"{src_lemma} → {tgt_lemma}", "masadiq_direct")

    # loanword check
    if status == "no_root":
        # Many no-root lemmas are direct loanwords
        src_ascii = src_lemma.replace('ا','a').replace('و','o').replace('ي','i')
        return (0.65, f"no_root status: likely loanword/foreign word '{src_lemma}' → '{tgt_lemma}'. Phonetic resemblance.",
                f"{src_lemma} (loanword) → {tgt_lemma}", "lemma_only")

    # Has profile but weak connection
    if axial:
        return (0.45, f"mafahim axial '{axial[:60]}' provides indirect link to '{tgt_lemma}'.",
                f"{src_lemma} (axial: {axial[:40]}) → {tgt_lemma}", "mafahim_deep")

    if short_gloss:
        return (0.40, f"masadiq gloss: '{short_gloss[:60]}'. Weak link to '{tgt_lemma}'.",
                f"{src_lemma} → {tgt_lemma}", "weak")

    return (0.30, f"Limited profile data for '{src_lemma}'. Speculative link to '{tgt_lemma}'.",
            f"{src_lemma} → {tgt_lemma}", "weak")


def main():
    # Load gold pairs
    pairs = []
    with open(GOLD_PATH, encoding="utf-8") as f:
        for line in f:
            d = json.loads(line)
            if d["source"]["lang"] == "ara" and d["target"]["lang"] == "eng":
                pairs.append(d)

    # Load profiles
    profiles = {}
    with open(PROFILES_PATH, encoding="utf-8") as f:
        for line in f:
            d = json.loads(line)
            profiles[d["lemma"]] = d

    results = []
    hit_count = 0
    fallback_count = 0

    for pair in pairs:
        src = pair["source"]["lemma"]
        tgt = pair["target"]["lemma"]
        src_gloss = pair["source"].get("gloss", "") or ""
        tgt_gloss = pair["target"].get("gloss", "") or ""
        profile = profiles.get(src, {})

        key = (src, tgt)
        if key in SCORES:
            score, reasoning, path, method = SCORES[key]
            hit_count += 1
        else:
            score, reasoning, path, method = fallback_score(
                src, tgt, src_gloss, tgt_gloss, profile
            )
            fallback_count += 1

        results.append({
            "source_lemma": src,
            "target_lemma": tgt,
            "lang_pair": "ara-eng",
            "semantic_score": score,
            "reasoning": reasoning,
            "path": path,
            "method": method,
            "annotator": "claude",
            "batch": "eye2_eng",
        })

    # Write output
    os.makedirs(os.path.dirname(OUTPUT_PATH), exist_ok=True)
    with open(OUTPUT_PATH, "w", encoding="utf-8") as f:
        for r in results:
            f.write(json.dumps(r, ensure_ascii=False) + "\n")

    # Summary
    scores_list = [r["semantic_score"] for r in results]
    mean_score = sum(scores_list) / len(scores_list)
    high = sum(1 for s in scores_list if s >= 0.80)
    mid = sum(1 for s in scores_list if 0.50 <= s < 0.80)
    low = sum(1 for s in scores_list if s < 0.50)

    method_counts = {}
    for r in results:
        method_counts[r["method"]] = method_counts.get(r["method"], 0) + 1

    print("=" * 60)
    print("Eye 2 Semantic Scores — ara-eng")
    print("=" * 60)
    print(f"Total pairs scored  : {len(results)}")
    print(f"From hand table     : {hit_count}")
    print(f"From fallback scorer: {fallback_count}")
    print(f"Mean semantic score : {mean_score:.3f}")
    print(f"High (>=0.80)       : {high}  ({100*high/len(results):.1f}%)")
    print(f"Mid  (0.50-0.79)    : {mid}  ({100*mid/len(results):.1f}%)")
    print(f"Low  (<0.50)        : {low}  ({100*low/len(results):.1f}%)")
    print()
    print("Methods breakdown:")
    for m, c in sorted(method_counts.items(), key=lambda x: -x[1]):
        print(f"  {m:25s}: {c}")
    print()
    print(f"Output written to: {OUTPUT_PATH}")


if __name__ == "__main__":
    main()
